var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……크윽!","JPN":"……うっ！","ENG":"...Kgh!","TWN":"……呃！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"가여운 것. 무리하고 있군.","JPN":"可哀想に。無理をしているな。","ENG":"Poor thing. You're struggling.","TWN":"可憐的傢伙。你在勉強自己啊。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"줄곧 방황하는 꼴이 위태로워 보여서 보고 있기 안쓰러울 정도야.","JPN":"彷徨ってばかりのざまが非常に危うくて、哀れに見えるくらいだ。","ENG":"It's almost sad to see you wandering about.","TWN":"你一直在彷徨的樣子讓人看了都覺得心疼。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네 예명인 백조처럼. 남들이 보지 않는 곳에서 기를 쓰고 발버둥 쳐왔겠지.","JPN":"お前の芸名である白鳥みたいに、見えないところで一生懸命足掻いてきたんだろう。","ENG":"Much like your stage name, I assume you frantically paddle underwater where no one is looking.","TWN":"就像你的藝名“天鵝”一樣。在別人看不到的地方，你一定拼盡全力，掙扎過吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그래서 이제 얼마나 남았지, 스완?","JPN":"それで、あとどれくらい残っている、スワン。","ENG":"How much of that do you have left, Swan?","TWN":"所以現在還剩多少，史旺？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"마왕의 권능으로 재조립한 그 잘난 거울도 이번 계획으로 꽤 많이 소모하고 말았을 텐데?","JPN":"魔王の権能で組み直した自慢の鏡も、この計画でだいぶ消費してしまったはずだ。","ENG":"I'm sure you must have consumed a lot of that Demon Lord-reassembled mirror of yours for this plan.","TWN":"用魔王的權能重新組裝的那面了不起的鏡子，這次計畫中也消耗了不少吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우습군요, 이지수.","JPN":"ふっ、笑えますね。ムラサメ・シノ。","ENG":"How amusing, Lee Jisoo.","TWN":"可笑之極，李智秀。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 매번 그런 식이에요.","JPN":"あなたはいつもそうです。","ENG":"You are always like this.","TWN":"你每次都是這樣。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 눈으로 상대를 훑고 나서, 마치 자기가 모든 것을 꿰뚫은 냥 떠들어대죠.","JPN":"人を品定めするような目をしては、すべてを分かりきったみたいに話す。","ENG":"You scan your opponent once and talk as if you have it all figured out.","TWN":"用那雙眼睛打量了對手後，就像自己看穿了一切似的喋喋不休。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서요? 지금 절 동정이라도 하겠다는 건가요?","JPN":"それで？　私のことを同情でもしているつもりですか？","ENG":"So? Are you trying to pity me right now?","TWN":"所以呢？你現在是想同情我嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 생각엔 당신도 별 반 다를 바 없는 것 같은데요. 어차피 이것도 대장님의…….","JPN":"私が思うに、あなたも大して変わらないはずです。どうせこれは隊長の……","ENG":"Because I think you aren't that different. After all, this is all Commander's–","TWN":"我覺得你也沒什麼不同。反正這也是隊長的……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"착각하지 마. 너도 알고 있을 텐데?","JPN":"勘違いするな。お前もわかっているだろう？","ENG":"Don't be mistaken. Because you know as well.","TWN":"別搞錯了。你應該知道吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"이 세계에서 네 고독을 참작해 줄 수 있는 사람은 네 과거를 엿보게 된 나뿐이라는 걸.","JPN":"この世界でお前の孤独を理解してあげられるのは、お前の過去を覗き込んだ私だけだということを。","ENG":"I am the only person in this world who can take your loneliness into account, the one who has gotten a glimpse of your past.","TWN":"在這個世界上，唯一能理解你孤獨的人，只有窺見你過去的我。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그러니 네가 나에게 스포일러를 남겼듯, 나도 너에게 점괘를 주도록 하지.","JPN":"だからお前が私にネタバレをしたように、今度は私がお前を占ってやろう。","ENG":"Much like how you left me a spoiler, let me give you your fortune-telling.","TWN":"所以，就像你給我留下了劇透一樣，我也會給你一個預言。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"너의 세계는 이미 멸망해버렸고, 네가 그 남자를 다시 보게 되는 날은 영영 오지 않아.","JPN":"お前の世界はすでに滅亡し、お前があの男にまた会う日は絶対に訪れない。","ENG":"Your world has already collapsed, and the day you see the man again will never come.","TWN":"你的世界已經毀滅了，你再也見不到那個男人了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"설령, 네가 <color=#ffd34c>세피라</color>라는 힘을 손에 넣는다고 할지라도.","JPN":"例え、<color=#ffd34c>セフィラ</color>という力を手に入れたとしても。","ENG":"Even if you obtain this power called <color=#ffd34c>Sephira</color>.","TWN":"即使你得到了<color=#ffd34c>塞菲拉</color>的力量。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"혹은 마왕으로부터 <color=#ffd34c>소원</color>을 양도받게 될지라도 말이지.","JPN":"あるいは、魔王から<color=#ffd34c>願い</color>を譲ってもらえたとしてもな。","ENG":"Or, you receive a <color=#ffd34c>wish</color> from a Demon Lord.","TWN":"或是從魔王那裡獲得了轉讓的<color=#ffd34c>願望</color>也說不定。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그것만큼은 절대 달라지지 않는 진실이야.","JPN":"それだけは決して変わらない真実だ。","ENG":"That is the absolute truth.","TWN":"這一點是絕對永遠不會改變的真理。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"검이 가볍군. 너도 어렴풋이 그 사실을 눈치채고 있지 않나?","JPN":"剣が軽いな。お前も何気にその事実に気付いているんじゃないか？","ENG":"Your sword feels light. I believe you were also vaguely aware of this, no?","TWN":"你的劍好輕啊。看來你也隱約察覺到了吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그러니까 이 세계의 관리자를 그 남자와 멋대로 겹쳐 보고 있는 거겠지.","JPN":"だからこの世界の管理者を、勝手にあの男と重ねているのだろう。","ENG":"That's why you have been seeing an overlap between this world's Administrator and the man.","TWN":"所以你才會把這個世界的管理者和那個男人隨意重疊在一起吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"첫 만남에 팬이라는 웃기지도 않는 이유를 대가면서 말이야.","JPN":"初対面なのにファンだというふざけた理由をつけてな。","ENG":"With a ridiculous reason of claiming that you said he was your fan when you first met him.","TWN":"第一次見面就說是粉絲，真是搞笑的理由。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 말대로…….","JPN":"あなたの言うとおり……","ENG":"Like you said...","TWN":"就像你說的……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어쩌면 당신 말대로, 단순히 무대 위에서의 배역이 겹칠 뿐일지도 모르겠죠.","JPN":"もしかしたら、あなたの言うとおり、単に舞台の上で配役が重なっているだけなのかもしれません。","ENG":"I might have simply been seeing an overlap between the roles on stage.","TWN":"也許僅僅是在舞台上的角色有所重疊而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 언제나 동경하고 있답니다.","JPN":"ですが、いつも憧れているんです。","ENG":"But I have always admired him.","TWN":"但我一直都很憧憬。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"백조와 같았던 그 남자를.","JPN":"白鳥のようだったあの男に。","ENG":"The man who was as graceful as a swan.","TWN":"那個如天鵝般的男人。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 이야기를 처음으로 되돌려 그 남자와 다시 만날 수 있다면…….","JPN":"すべての物語を振り出しに戻し、あの男とまた会えるのなら……","ENG":"If I can meet him again by reverting the story to its beginning...","TWN":"如果能將所有的故事重頭再來，和那個人再次相遇……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"나의 고향, 나의 무대를 다시 한번 마주할 수 있다면…….","JPN":"私の故郷、私の舞台をもう一度踏むことができるのなら……","ENG":"If I can see my hometown and my stage once more...","TWN":"如果能再次面對我的故鄉，我的舞台……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"나는 무엇이든 할 수 있어요.","JPN":"私は何でもできます。","ENG":"I'll do anything for it.","TWN":"我什麼都願意做。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그런가. 그렇다면 대답은 하나뿐이겠지.","JPN":"そうか。なら、答えは一つだけ。","ENG":"I see. Then I have only one thing to tell you.","TWN":"是嗎。那麼答案只有一個了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"이제 그 헛된 꿈에서 깨어날 시간이야. 스완 클레어.","JPN":"もう夢から目覚める時間だ。スワン・クレア。","ENG":"It's time to wake up from this vain dream, Swan Claire.","TWN":"現在是時候從那個虛幻的夢裡醒來了，史旺·克萊爾。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};